using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine($"Build succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors
var errors = build.FindChildrenRecursive<Error>();
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();

// Collect all warnings  
var warnings = build.FindChildrenRecursive<Warning>();
Console.WriteLine($"Total warnings: {warnings.Count}");
Console.WriteLine();

// Print project structure
Console.WriteLine("=== PROJECT STRUCTURE ===");
foreach (var project in build.FindChildrenRecursive<Project>())
{
    Console.WriteLine($"Project: {project.Name} (Succeeded: {project.Succeeded})");
}
Console.WriteLine();

// Print all errors with context
Console.WriteLine("=== ERRORS ===");
foreach (var error in errors)
{
    var parent = error.Parent;
    string projectName = "unknown";
    while (parent != null)
    {
        if (parent is Project p)
        {
            projectName = p.Name;
            break;
        }
        parent = parent.Parent;
    }
    Console.WriteLine($"[{projectName}] {error.Code}: {error.Text}");
    if (!string.IsNullOrEmpty(error.File))
        Console.WriteLine($"  File: {error.File}:{error.LineNumber}");
    Console.WriteLine();
}

// Print all warnings
Console.WriteLine("=== WARNINGS ===");
foreach (var warning in warnings)
{
    var parent = warning.Parent;
    string projectName = "unknown";
    while (parent != null)
    {
        if (parent is Project p)
        {
            projectName = p.Name;
            break;
        }
        parent = parent.Parent;
    }
    Console.WriteLine($"[{projectName}] {warning.Code}: {warning.Text}");
    if (!string.IsNullOrEmpty(warning.File))
        Console.WriteLine($"  File: {warning.File}:{warning.LineNumber}");
    Console.WriteLine();
}

// Extract embedded files from binlog if possible
Console.WriteLine("=== SOURCE FILES IN BINLOG ===");
var sourceFiles = build.FindChildrenRecursive<SourceFile>();
foreach (var sf in sourceFiles)
{
    Console.WriteLine($"  {sf.Name}");
}
