using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Extract all embedded source/project files
Console.WriteLine("=== ARCHIVED FILES ===");
var archive = build.FindChild<SourceFilesArchive>();
if (archive != null)
{
    foreach (var file in archive.Children)
    {
        if (file is SourceFile sf)
        {
            Console.WriteLine($"\n--- {sf.Name} ---");
            Console.WriteLine(sf.Value);
        }
    }
}
else
{
    Console.WriteLine("No archive found, checking for embedded files...");
    // Try finding files through the tree
    build.VisitAllChildren<NameValueNode>(n => {
        if (n.Name != null && (n.Name.EndsWith(".cs") || n.Name.EndsWith(".csproj") || n.Name.EndsWith(".sln")))
        {
            Console.WriteLine($"\n--- {n.Name} ---");
            if (!string.IsNullOrEmpty(n.Value))
                Console.WriteLine(n.Value);
        }
    });
}
