cat > /tmp/binlog-reader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Walk the entire tree looking for any node that might contain file content
Console.WriteLine("=== ALL NODE TYPES ===");
var typeSet = new HashSet<string>();
build.VisitAllChildren<BaseNode>(n => {
    typeSet.Add(n.GetType().Name);
});
foreach (var t in typeSet.OrderBy(x => x))
    Console.WriteLine($"  {t}");

Console.WriteLine();

// Look for SourceFile nodes
Console.WriteLine("=== SOURCE FILES ===");
build.VisitAllChildren<SourceFile>(sf => {
    Console.WriteLine($"SourceFile: {sf.Name} (type={sf.GetType().Name})");
    // Print all public properties
    foreach (var prop in sf.GetType().GetProperties())
    {
        try
        {
            var val = prop.GetValue(sf);
            if (val != null && val.ToString() != sf.GetType().FullName)
                Console.WriteLine($"  {prop.Name} = {val.ToString()?.Substring(0, Math.Min(200, val.ToString()?.Length ?? 0))}");
        }
        catch { }
    }
});

Console.WriteLine();

// Check for the embedded archive
Console.WriteLine("=== TOP-LEVEL CHILDREN ===");
foreach (var child in build.Children)
{
    Console.WriteLine($"  {child.GetType().Name}: {child}");
    if (child is TreeNode tn)
    {
        foreach (var grandchild in tn.Children.Take(10))
        {
            Console.WriteLine($"    {grandchild.GetType().Name}: {grandchild}");
        }
    }
}
