var binlogPath = args[0];

// Use BinLogReader to read raw records and find embedded files
var reader = new BinLogReader();
var embeddedFiles = new Dictionary<string, string>();

foreach (var record in reader.ReadRecords(binlogPath))
{
    if (record.Args is Microsoft.Build.Framework.BuildMessageEventArgs msg)
    {
        // Check if this has file content
    }
}

// Try reading the archive directly
var build = BinaryLog.ReadBuild(binlogPath);

// Look at the References for Services.csproj to understand what's missing
Console.WriteLine("=== SERVICES.CSPROJ REFERENCES ===");
build.VisitAllChildren<CscTask>(csc => {
    var parent = csc.Parent;
    string projectName = "";
    while (parent != null)
    {
        if (parent is Project p) { projectName = p.Name; break; }
        parent = parent.Parent;
    }
    if (projectName != "Services.csproj") return;

    foreach (var child in csc.Children)
    {
        if (child is Folder f && f.Name == "Parameters")
        {
            foreach (var param in f.Children)
            {
                if (param is Parameter p && p.Name == "References")
                {
                    Console.WriteLine("References:");
                    foreach (var item in p.Children)
                        Console.WriteLine($"  {item}");
                }
                if (param is Parameter p2 && p2.Name == "Sources")
                {
                    Console.WriteLine("Sources:");
                    foreach (var item in p2.Children)
                        Console.WriteLine($"  {item}");
                }
            }
        }
    }
});

// Check Api.csproj - did it even attempt to compile?
Console.WriteLine("\n=== API.CSPROJ COMPILATION STATUS ===");
bool apiCscFound = false;
build.VisitAllChildren<CscTask>(csc => {
    var parent = csc.Parent;
    while (parent != null)
    {
        if (parent is Project p && p.Name == "Api.csproj") { apiCscFound = true; break; }
        parent = parent.Parent;
    }
});
Console.WriteLine($"Api.csproj Csc task found: {apiCscFound}");

// Check if Api build was skipped/failed due to dependency
Console.WriteLine("\n=== API PROJECT BUILD TARGETS ===");
build.VisitAllChildren<Target>(t => {
    var parent = t.Parent;
    while (parent != null)
    {
        if (parent is Project p && p.Name == "Api.csproj") 
        {
            if (t.Name.Contains("Build") || t.Name.Contains("Compile") || t.Name.Contains("ResolveProjectReferences"))
                Console.WriteLine($"  Target: {t.Name}");
            break;
        }
        parent = parent.Parent;
    }
});

// Look for MSBuild tasks that reference dependent projects
Console.WriteLine("\n=== MSBUILD TASK (project-to-project references) ===");
build.VisitAllChildren<MSBuildTask>(msbuild => {
    var parent = msbuild.Parent;
    string projectName = "";
    while (parent != null)
    {
        if (parent is Project p) { projectName = p.Name; break; }
        parent = parent.Parent;
    }
    if (projectName == "Api.csproj")
    {
        Console.WriteLine($"MSBuildTask in {projectName}:");
        foreach (var child in msbuild.Children.Take(5))
            Console.WriteLine($"  {child.GetType().Name}: {child}");
    }
});

// Extract the embedded source files from the binlog archive
