        var typeName = args2.GetType().Name;
        // Look for ProjectImportedEventArgs which sometimes embed source files
        if (typeName.Contains("Archive") || typeName.Contains("Embed"))
        {
            Console.WriteLine($"Found record type: {typeName}");
        }
    }
}

