// Walk all children looking for anything that looks like source file storage
build.VisitAllChildren<BaseNode>(n => {
    var typeName = n.GetType().Name;
    if (typeName.Contains("Archive") || typeName.Contains("Source") || typeName.Contains("Embed"))
    {
        Console.WriteLine($"  Type: {typeName}, ToString: {n.ToString()?.Substring(0, Math.Min(200, n.ToString()?.Length ?? 0))}");
    }
});

// 5) Use the savefiles utility from the binlogtool to extract actual .cs content
// Since we know the file paths, let's look at what the compilation was actually fed
Console.WriteLine("\n=== FULL COMMAND LINE FOR SERVICES CSC ===");
build.VisitAllChildren<CscTask>(csc => {
    var parent = csc.Parent;
    string projectName = "";
    while (parent != null) { if (parent is Project p) { projectName = p.Name; break; } parent = parent.Parent; }
    if (projectName != "Services.csproj") return;
    foreach (var child in csc.Children)
    {
        if (child is Property prop && prop.Name == "CommandLineArguments")
        {
            Console.WriteLine(prop.Value);
        }
    }
});
